import { useState } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import HomeScreen from './screens/HomeScreen';
import ProductScreen from './screens/ProductScreen';
import CartScreen from './screens/CartScreen';
import LoginScreen from './screens/LoginScreen';
import RegisterScreen from './screens/RegisterScreen';
import ShippingScreen from './screens/ShippingScreen';
import ProfileScreen from './screens/ProfileScreen';
import AdminScreen from './screens/AdminScreen';
import books from './product_list';
import './App.css';

function App() {
  const [screen, setScreen] = useState('home');
  const [selectedBookId, setSelectedBookId] = useState(books[0].id);
  const [cartItems, setCartItems] = useState([]);
  const [user, setUser] = useState(null);

  const selectedBook = books.find((book) => book.id === selectedBookId) || books[0];

  function openBook(id) {
    setSelectedBookId(id);
    setScreen('product');
  }

  function addToCart(book) {
    setCartItems((current) => {
      if (current.some((item) => item.id === book.id)) {
        return current;
      }

      return [...current, { ...book, days: 21 }];
    });
    setScreen('cart');
  }

  function login(email, name = 'Ana Dzanic') {
    setUser({ name, email, isAdmin: email.toLowerCase().includes('admin') });
    setScreen('home');
  }

  function logout() {
    setUser(null);
    setScreen('home');
  }

  function checkout() {
    if (!user) {
      setScreen('login');
      return;
    }

    setScreen('shipping');
  }

  return (
    <>
      <Header
        cartCount={cartItems.length}
        onLogout={logout}
        screen={screen}
        setScreen={setScreen}
        user={user}
      />
      <main className="container main-content">
        {screen === 'home' && <HomeScreen onOpen={openBook} />}
        {screen === 'product' && (
          <ProductScreen book={selectedBook} onAddToCart={addToCart} onBack={() => setScreen('home')} />
        )}
        {screen === 'cart' && (
          <CartScreen
            cartItems={cartItems}
            onCheckout={checkout}
            onRemove={(id) => setCartItems((current) => current.filter((item) => item.id !== id))}
          />
        )}
        {screen === 'login' && <LoginScreen onLogin={login} onRegister={() => setScreen('register')} />}
        {screen === 'register' && <RegisterScreen onLogin={login} />}
        {screen === 'shipping' && <ShippingScreen onSubmit={() => setScreen('profile')} />}
        {screen === 'profile' && user && <ProfileScreen cartItems={cartItems} user={user} />}
        {screen === 'admin' && <AdminScreen />}
      </main>
      <Footer />
    </>
  );
}

export default App;
